import{_ as t,o as l,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Browse & Filter Players","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/players-directory.md","filePath":"how-to/players-directory.md"}'),i={name:"how-to/players-directory.md"};function o(s,e,n,h,c,p){return l(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="browse-filter-players" tabindex="-1">Browse &amp; Filter Players <a class="header-anchor" href="#browse-filter-players" aria-label="Permalink to &quot;Browse &amp; Filter Players&quot;">â€‹</a></h1><p>The <strong>Players</strong> page is the main working list for player records. It helps you find people quickly, narrow the list to the right scope, and open the next action you need.</p><blockquote><p>Screenshot placeholder: players-list.png</p></blockquote><h2 id="what-this-page-is-for" tabindex="-1">What this page is for <a class="header-anchor" href="#what-this-page-is-for" aria-label="Permalink to &quot;What this page is for&quot;">â€‹</a></h2><p>Use the directory to:</p><ul><li>switch kingdom or alliance context</li><li>search by player name</li><li>filter by status, attribute, reward state, or API state</li><li>sort the table</li><li>open a player profile</li><li>kick, edit, sync, delete, or restore a player when your role allows it</li></ul><h2 id="start-with-the-context-section" tabindex="-1">Start with the context section <a class="header-anchor" href="#start-with-the-context-section" aria-label="Permalink to &quot;Start with the context section&quot;">â€‹</a></h2><p>The <strong>Context</strong> area is important because it controls which players you are looking at.</p><p>You can usually narrow by:</p><ul><li>kingdom</li><li>alliance</li><li>search text</li><li>status</li><li>attribute</li><li>reward state</li><li>API state</li></ul><p>Admins can also use <strong>Show deleted</strong> to include deleted players in the list.</p><h2 id="read-the-table" tabindex="-1">Read the table <a class="header-anchor" href="#read-the-table" aria-label="Permalink to &quot;Read the table&quot;">â€‹</a></h2><p>The <strong>Player Directory</strong> table shows a compact view of:</p><ul><li>player name</li><li>current scope</li><li>profile ID link state</li><li>API sync state</li><li>level</li><li>alliance role</li><li>status</li><li>attributes</li><li>participation</li><li>results count</li></ul><h2 id="common-actions-from-the-list" tabindex="-1">Common actions from the list <a class="header-anchor" href="#common-actions-from-the-list" aria-label="Permalink to &quot;Common actions from the list&quot;">â€‹</a></h2><ul><li>Open the player profile.</li><li>Sync the Kingshot profile for a linked player.</li><li>Kick the player from the current alliance.</li><li>Edit the player.</li><li>Delete the player.</li><li>Restore a deleted player.</li></ul><p>What you see depends on your role and your current scope.</p><h2 id="helpful-filters" tabindex="-1">Helpful filters <a class="header-anchor" href="#helpful-filters" aria-label="Permalink to &quot;Helpful filters&quot;">â€‹</a></h2><ul><li>Use <strong>API linked</strong> and <strong>local only</strong> when checking sync coverage.</li><li>Use <strong>reward eligible</strong> when reviewing reward-readiness.</li><li>Use the attribute filter when you are tracking a manual or analytics-driven segment.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">â€‹</a></h2><ul><li><a href="./add-player.html">Add a Player</a></li><li><a href="./edit-player.html">Edit Player Details</a></li><li><a href="./player-profile.html">Read a Player Profile</a></li><li><a href="./player-sync.html">Sync Players from the Game API</a></li></ul>',21)])])}const y=t(i,[["render",o]]);export{u as __pageData,y as default};
